import { http, HttpResponse } from 'msw';

const mockWikipediaPage1 = {
  pageid: 736,
  title: 'Albert Einstein',
  varianttitles: { en: 'Albert Einstein' },
  extract:
    'Albert Einstein was a German-born theoretical physicist who is widely held to be one of the greatest and most influential scientists of all time. Best known for developing the theory of relativity, he also made important contributions to quantum mechanics.',
  thumbnail: {
    source:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d3/Albert_Einstein_Head.jpg/800px-Albert_Einstein_Head.jpg',
    width: 800,
    height: 1000,
  },
  canonicalurl: 'https://en.wikipedia.org/wiki/Albert_Einstein',
};

const mockWikipediaPage2 = {
  pageid: 18599,
  title: 'Mount Everest',
  varianttitles: { en: 'Mount Everest' },
  extract:
    "Mount Everest is Earth's highest mountain above sea level, located in the Mahalangur Himal sub-range of the Himalayas. The China–Nepal border runs across its summit point.",
  thumbnail: {
    source:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg/800px-Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg',
    width: 800,
    height: 600,
  },
  canonicalurl: 'https://en.wikipedia.org/wiki/Mount_Everest',
};

const mockWikipediaPage3 = {
  pageid: 5042916,
  title: 'The Eiffel Tower',
  varianttitles: { en: 'Eiffel Tower' },
  extract:
    'The Eiffel Tower is a wrought-iron lattice tower on the Champ de Mars in Paris, France. It is named after the engineer Gustave Eiffel, whose company designed and built the tower from 1887 to 1889.',
  thumbnail: {
    source:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/a/a8/Tour_Eiffel_Wikimedia_Commons.jpg/800px-Tour_Eiffel_Wikimedia_Commons.jpg',
    width: 800,
    height: 1200,
  },
  canonicalurl: 'https://en.wikipedia.org/wiki/Eiffel_Tower',
};

export const mswHandlers = {
  wikipedia: [
    http.get(/wikipedia\.org\/w\/api\.php/, () =>
      HttpResponse.json({
        query: {
          pages: {
            '736': mockWikipediaPage1,
            '18599': mockWikipediaPage2,
            '5042916': mockWikipediaPage3,
          },
        },
      })
    ),
  ],
};

import type { Preview } from '@storybook/react-vite';
import { initialize, mswLoader } from 'msw-storybook-addon';
import '../src/index.css';
import { LikedArticlesProvider } from '../src/contexts/LikedArticlesContext';
import { mswHandlers } from './msw-handlers';

initialize({
  onUnhandledRequest: 'bypass',
});

const preview: Preview = {
  decorators: [
    (Story) => (
      <LikedArticlesProvider>
        <Story />
      </LikedArticlesProvider>
    ),
  ],
  loaders: [mswLoader],
  parameters: {
    controls: {
      matchers: {
        color: /(background|color)$/i,
        date: /Date$/i,
      },
    },
    a11y: {
      test: 'todo',
    },
    msw: {
      handlers: mswHandlers,
    },
  },
  async beforeEach() {
    localStorage.setItem('lang', 'en');
    localStorage.setItem('likedArticles', JSON.stringify([]));
  },
};

export default preview;

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, within } from 'storybook/test';
import Article from './Article';

const meta = {
  component: Article,
} satisfies Meta<typeof Article>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  render: () => (
    <Article
      title="Albert Einstein"
      content="Albert Einstein was a German-born theoretical physicist who is widely held to be one of the greatest and most influential scientists of all time."
    />
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByRole('article')).toBeVisible();
    await expect(canvas.getByText('Albert Einstein')).toBeVisible();
    await expect(canvas.getByText(/German-born theoretical physicist/i)).toBeVisible();
  },
};

export const WithImage: Story = {
  render: () => (
    <Article
      title="Mount Everest"
      content="Mount Everest is Earth's highest mountain above sea level, located in the Mahalangur Himal sub-range of the Himalayas."
      image="https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg/800px-Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg"
    />
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByRole('article')).toBeVisible();
    await expect(canvas.getByText('Mount Everest')).toBeVisible();
    await expect(canvas.getByAltText(/Illustration for article: Mount Everest/i)).toBeVisible();
  },
};

export const LongContent: Story = {
  render: () => (
    <Article
      title="The Eiffel Tower"
      content="The Eiffel Tower is a wrought-iron lattice tower on the Champ de Mars in Paris, France. It is named after the engineer Gustave Eiffel, whose company designed and built the tower from 1887 to 1889. Locally nicknamed 'La dame de fer' (French for 'Iron Lady'), it was constructed as the centerpiece of the 1889 World's Fair, and to crown the centennial celebration of the French Revolution. Although initially criticised by some of France's leading artists and intellectuals for its design, it has since become a global cultural icon of France and one of the most recognisable structures in the world."
    />
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByRole('article')).toBeVisible();
    await expect(canvas.getByText('The Eiffel Tower')).toBeVisible();
    await expect(canvas.getByText(/wrought-iron lattice tower/i)).toBeVisible();
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, within, userEvent } from 'storybook/test';
import ArticleList from './ArticleList';

const meta = {
  component: ArticleList,
} satisfies Meta<typeof ArticleList>;

export default meta;
type Story = StoryObj<typeof meta>;

const sampleArticles = [
  {
    id: 1,
    title: 'Albert Einstein',
    content:
      'Albert Einstein was a German-born theoretical physicist who is widely held to be one of the greatest and most influential scientists of all time.',
  },
  {
    id: 2,
    title: 'Mount Everest',
    content:
      "Mount Everest is Earth's highest mountain above sea level, located in the Mahalangur Himal sub-range of the Himalayas.",
    image:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg/800px-Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg',
  },
  {
    id: 3,
    title: 'Eiffel Tower',
    content:
      'The Eiffel Tower is a wrought-iron lattice tower on the Champ de Mars in Paris, France.',
  },
];

export const Default: Story = {
  render: () => <ArticleList articles={sampleArticles} />,
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByRole('navigation', { name: /Articles navigation/i })).toBeVisible();
    await expect(canvas.getByText('Albert Einstein')).toBeVisible();
    await expect(canvas.getByText('Mount Everest')).toBeVisible();
    await expect(canvas.getByText('Eiffel Tower')).toBeVisible();
  },
};

export const SingleArticle: Story = {
  render: () => (
    <ArticleList
      articles={[
        {
          id: 1,
          title: 'Albert Einstein',
          content:
            'Albert Einstein was a German-born theoretical physicist who developed the theory of relativity.',
        },
      ]}
    />
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByRole('navigation', { name: /Articles navigation/i })).toBeVisible();
    await expect(canvas.getByText('Albert Einstein')).toBeVisible();
    const items = canvas.getAllByRole('listitem');
    await expect(items).toHaveLength(1);
  },
};

export const WithOnSelect: Story = {
  render: () => {
    const handleSelect = (article: { title: string }) => {
      console.log('Selected:', article.title);
    };
    return <ArticleList articles={sampleArticles} onArticleSelect={handleSelect} />;
  },
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByText('Albert Einstein')).toBeVisible();
    const firstItem = canvas.getAllByRole('listitem')[0];
    await userEvent.click(firstItem);
    await expect(firstItem).toBeVisible();
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, within, userEvent } from 'storybook/test';
import { WikiCard } from './WikiCard';
import type { WikiArticle } from './WikiCard';

const meta = {
  component: WikiCard,
} satisfies Meta<typeof WikiCard>;

export default meta;
type Story = StoryObj<typeof meta>;

const einsteinArticle: WikiArticle = {
  pageid: 736,
  title: 'Albert Einstein',
  displaytitle: 'Albert Einstein',
  extract:
    'Albert Einstein was a German-born theoretical physicist who is widely held to be one of the greatest and most influential scientists of all time. Best known for developing the theory of relativity.',
  thumbnail: {
    source:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d3/Albert_Einstein_Head.jpg/800px-Albert_Einstein_Head.jpg',
    width: 800,
    height: 1000,
  },
  url: 'https://en.wikipedia.org/wiki/Albert_Einstein',
};

const everestArticle: WikiArticle = {
  pageid: 18599,
  title: 'Mount Everest',
  displaytitle: 'Mount Everest',
  extract:
    "Mount Everest is Earth's highest mountain above sea level, located in the Mahalangur Himal sub-range of the Himalayas.",
  thumbnail: {
    source:
      'https://upload.wikimedia.org/wikipedia/commons/thumb/e/e7/Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg/800px-Everest_North_Face_toward_Base_Camp_Tibet_Luca_Galuzzi_2006.jpg',
    width: 800,
    height: 600,
  },
  url: 'https://en.wikipedia.org/wiki/Mount_Everest',
};

const noThumbnailArticle: WikiArticle = {
  pageid: 99999,
  title: 'Text Only Article',
  displaytitle: 'Text Only Article',
  extract:
    'This is an article without a thumbnail image. It should render a gray background instead.',
  thumbnail: {
    source: '',
    width: 0,
    height: 0,
  },
  url: 'https://en.wikipedia.org/wiki/Text_Only_Article',
};

export const Default: Story = {
  render: () => (
    <div className="h-screen w-full bg-black text-white">
      <WikiCard article={einsteinArticle} />
    </div>
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByText('Albert Einstein')).toBeVisible();
    await expect(canvas.getByText(/German-born theoretical physicist/i)).toBeVisible();
    await expect(canvas.getByRole('button', { name: /like article/i })).toBeVisible();
    await expect(canvas.getByRole('button', { name: /share article/i })).toBeVisible();
    await expect(canvas.getByRole('link', { name: /read more/i })).toBeVisible();
  },
};

export const Liked: Story = {
  render: () => (
    <div className="h-screen w-full bg-black text-white">
      <WikiCard article={everestArticle} />
    </div>
  ),
  async beforeEach() {
    localStorage.setItem('likedArticles', JSON.stringify([everestArticle]));
  },
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    await expect(canvas.getByText('Mount Everest')).toBeVisible();
    const likeButton = canvas.getByRole('button', { name: /like article/i });
    await expect(likeButton).toBeVisible();
    await expect(likeButton).toHaveClass('bg-red-500');
  },
};

export const LikeInteraction: Story = {
  render: () => (
    <div className="h-screen w-full bg-black text-white">
      <WikiCard article={einsteinArticle} />
    </div>
  ),
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);
    const likeButton = canvas.getByRole('button', { name: /like article/i });
    await expect(likeButton).not.toHaveClass('bg-red-500');
    await userEvent.click(likeButton);
    await expect(likeButton).toHaveClass('bg-red-500');
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, within, userEvent } from 'storybook/test';
import { LanguageSelector } from './LanguageSelector';

const meta = {
