    const canvas = within(canvasElement);
    await expect(canvas.getByRole('button', { name: /language/i })).toBeVisible();
  },
};

export const DropdownOpen: Story = {
  render: () => (
    <div className="bg-black p-4 flex justify-end" style={{ minHeight: '300px' }}>
      <LanguageSelector />
    </div>
